VIEW: AppMasterDB.dbo.Job_Progress_Report_GB
                PURPOSE: Main job progress tracking - most comprehensive view with weekly buckets, purpose values, WBS
                SOURCE TABLES: dbo.WMR, dbo.WMR_TaskPlan_csv_imported, dbo.Job_Progress_PlanSnapshot, dbo.task_daily, dbo.ProjectIDs, dbo.data_table_sched_jsons, dbo.WBS_Master_Tracker_

                KEY COLUMNS:
                {
  "Well ID": {
    "type": "nvarchar",
    "derived_from": "WMR_TaskPlan_csv_imported.New_Well_ID",
    "logic": "LTRIM(RTRIM(TRY_CONVERT(nvarchar(50), tp.New_Well_ID)))"
  },
  "Well Name / Project Name": {
    "type": "nvarchar",
    "derived_from": "WMR.well_name_after_spud",
    "logic": "MAX(well_name_after_spud) GROUP BY pdo_well_id"
  },
  "Category": {
    "type": "nvarchar",
    "derived_from": "ProjectIDs.column2",
    "logic": "JOIN on project_id"
  },
  "PO No": {
    "type": "nvarchar",
    "logic": "IF category contains flowline/cwf/rwf THEN flow_line_po_no ELSE location_po_no"
  },
  "WBS No": {
    "type": "nvarchar",
    "logic": "OUTER APPLY WBS_Master_Tracker_ with category matching"
  },
  "Cum-Prior Month Actual %": {
    "type": "decimal(18,2)",
    "logic": "prior actual fraction * 100"
  },
  "Week-1 Plan %": {
    "type": "decimal(18,2)",
    "logic": "W1_Plan_frac * 100, NULL if no plan"
  },
  "Week-1 Actual %": {
    "type": "decimal(18,2)",
    "logic": "W1_Act_frac * 100"
  },
  "Week-2 Plan %": {
    "type": "decimal(18,2)",
    "logic": "W2_Plan_frac * 100"
  },
  "Week-2 Actual %": {
    "type": "decimal(18,2)",
    "logic": "W2_Act_frac * 100"
  },
  "Week-3 Plan %": {
    "type": "decimal(18,2)",
    "logic": "W3_Plan_frac * 100"
  },
  "Week-3 Actual %": {
    "type": "decimal(18,2)",
    "logic": "W3_Act_frac * 100"
  },
  "Week-4 Plan %": {
    "type": "decimal(18,2)",
    "logic": "W4_Plan_frac * 100"
  },
  "Week-4 Actual %": {
    "type": "decimal(18,2)",
    "logic": "W4_Act_frac * 100"
  },
  "Week-5 Plan %": {
    "type": "decimal(18,2)",
    "logic": "W5_Plan_frac * 100"
  },
  "Week-5 Actual %": {
    "type": "decimal(18,2)",
    "logic": "W5_Act_frac * 100"
  },
  "Current Month Plan %": {
    "type": "decimal(18,2)",
    "logic": "SUM(W1-W5_Plan_frac) * 100, capped at 1.0"
  },
  "Current Month Actual %": {
    "type": "decimal(18,2)",
    "logic": "SUM(W1-W5_Act_frac) * 100, capped at 1.0"
  },
  "Cum-Current Month Plan %": {
    "type": "decimal(18,2)",
    "logic": "CumCurrentMonthPlanFrac * 100"
  },
  "Cum-Current Month Actual %": {
    "type": "decimal(18,2)",
    "logic": "SUM(CumPrior + W1-W5) * 100, capped at 1.0"
  },
  "Purpose Value": {
    "type": "decimal(28,2)",
    "logic": "SUM(schedule purpose_value) from SchedAgg"
  },
  "Cum-Prior Month Plan": {
    "type": "decimal(28,2)",
    "logic": "PurposeValue * Cum_Prior_Plan_frac"
  },
  "Cum-Prior Month Actual": {
    "type": "decimal(28,2)",
    "logic": "PurposeValue * Cum_Prior_Act_frac"
  },
  "Current month Plan": {
    "type": "decimal(28,2)",
    "logic": "PurposeValue * CurrentMonthPlanFrac"
  },
  "Current Month Actual": {
    "type": "decimal(28,2)",
    "logic": "PurposeValue * SUM(W1-W5_Act_frac)"
  },
  "Target End": {
    "type": "date",
    "logic": "COALESCE(snapshot, max from Base)"
  }
}

                BUSINESS LOGIC:
                {
  "weightage_normalization": "If contains '%', remove and divide by 100. If > 1.0, divide by 100. If <= 1.0, use as-is",
  "progress_normalization": "Same as weightage - normalize to 0-1 fraction",
  "week_buckets": "W1=day1-7, W2=day8-14, W3=day15-21, W4=day22-28, W5=day29+",
  "actual_calculation_part1": "If actual_start AND actual_end exist AND valid: daily_frac = (progress_frac * weight_frac) / days",
  "actual_calculation_part2": "Fallback to task_daily when no valid date range: qty/qty_total * weight_frac",
  "plan_source": "From Job_Progress_PlanSnapshot table - weekly fractions",
  "cluster_derivation": "Source='NC-WD'\u2192nimr, Source='MC-WD'\u2192marmul from data_table_sched_jsons",
  "project_code_parsing": "Extract from filename: SCHED-XXXX-RIG \u2192 XXXX"
}

                SQL PATTERNS:
                {
  "weight_frac": "CASE WHEN weightage LIKE '%' THEN REPLACE/100 WHEN weightage > 1 THEN weightage/100 ELSE weightage END",
  "week_bucket": "CASE WHEN day BETWEEN 1 AND 7 THEN 'W1' WHEN 8-14 THEN 'W2' etc",
  "cap_at_1": "CASE WHEN sum > 1 THEN 1.0 ELSE sum END",
  "well_id_extract": "LTRIM(RTRIM(TRY_CONVERT(nvarchar(50), New_Well_ID)))"
}

VIEW: AppMasterDB.dbo.vw_JobProgress
                PURPOSE: Alternative job progress - simpler, monthly focus with category from ProjectIDs
                SOURCE TABLES: dbo.ActivityTaskPlan, dbo.ProjectIDs, dbo.WMR

                KEY COLUMNS:
                {
  "Category": {
    "type": "nvarchar",
    "logic": "ProjectIDs.column2"
  },
  "Well ID / Project ID": {
    "type": "int",
    "logic": "Extract from code after '-'"
  },
  "Week-1 Plan %": {
    "type": "decimal(10,2)",
    "logic": "SUM(weightage) WHERE target_start day 1-7"
  },
  "Week-1 Actual %": {
    "type": "decimal(10,2)",
    "logic": "SUM(weightage * progress_ratio) WHERE actual_start day 1-7"
  }
}

                BUSINESS LOGIC:
                {
  "well_id_from_code": "RIGHT(code, LEN(code) - CHARINDEX('-', code))",
  "week_definition": "Week1=1-7, Week2=8-14, Week3=15-21, Week4=22-28, Week5=29+",
  "progress_ratio": "1 or 100\u21921.0, 0.10\u21920.10, 10\u21920.10"
}

                SQL PATTERNS:
                {}

VIEW: AppMasterDB.dbo.vw_JOB_COST
                PURPOSE: Job cost - planned vs actual resources (employees, equipment)
                SOURCE TABLES: dbo.task_daily, dbo.Revenue, dbo.crews, dbo.Employee, dbo.company_employees, dbo.EmployeeType, dbo.Equipment, dbo.EquipmentType, dbo.ActivityMasterMapping

                KEY COLUMNS:
                {
  "Project": {
    "type": "nvarchar",
    "logic": "Revenue.rigcode - the rig identifier"
  },
  "Well ID": {
    "type": "nvarchar",
    "logic": "task_daily.well_id"
  },
  "Activity ID": {
    "type": "nvarchar",
    "logic": "LEFT(task_code, 8) - first 8 characters"
  },
  "crew code": {
    "type": "nvarchar",
    "logic": "task_daily.crew_code \u2192 crews.Code"
  },
  "Plan Employee Name": {
    "type": "nvarchar",
    "logic": "FROM crews.Employees JSON \u2192 Employee table"
  },
  "Actual Employee Name": {
    "type": "nvarchar",
    "logic": "FROM task_daily.employee_ids_text JSON \u2192 Employee"
  },
  "Effective Work Hours": {
    "type": "decimal",
    "logic": "JSON_VALUE(daily_data, '$.actual_hours')"
  }
}

                BUSINESS LOGIC:
                {
  "activity_extraction": "LEFT(LTRIM(RTRIM(task_code)), 8)",
  "crew_json_explode": "OPENJSON(c.Employees) to get employee IDs",
  "resource_pairing": "Full outer join Planned vs Actual on: well_id + ActionOn + ActivityID + resource_type + PGCode + rn",
  "project_prefix": "M\u2192MML, N\u2192NIM from first letter of rigcode"
}

                SQL PATTERNS:
                {}

VIEW: AppMasterDB.dbo.PH_Productivity
                PURPOSE: Productivity tracking - QHSE Supervisor and Crew performance
                SOURCE TABLES: dbo.task_daily, dbo.Employee, dbo.ActivityCodesNorms, dbo.CrewType

                KEY COLUMNS:
                {
  "Year": {
    "type": "int",
    "logic": "YEAR from ActionOn"
  },
  "Month": {
    "type": "int",
    "logic": "MONTH from ActionOn"
  },
  "PA Name": {
    "type": "nvarchar",
    "logic": "LEFT(task_assignee, CHARINDEX('.', task_assignee)-1)"
  },
  "PH Name": {
    "type": "nvarchar",
    "logic": "Employee.Email = supervisor_email \u2192 Employee.Name"
  },
  "PH Emp ID": {
    "type": "nvarchar",
    "logic": "Employee.UId"
  },
  "Crew Name": {
    "type": "nvarchar",
    "logic": "CrewType.Description WHERE Code = REPLACE(crew_type, '-', '')"
  },
  "Avg_Productivity_Pct": {
    "type": "decimal",
    "logic": "(SUM(data_qty)/SUM(data_hours)) / Norms * 100"
  },
  "W1_PI_T_Wise": {
    "type": "decimal",
    "logic": "Week 1 Productivity Index T-Wise"
  },
  "W1_PI_CMR": {
    "type": "decimal",
    "logic": "Week 1 Productivity Index CMR"
  }
}

                BUSINESS LOGIC:
                {
  "productivity_formula": "Productivity% = (QtyPerHour / Norms) * 100",
  "ph_lookup": "supervisor_email \u2192 Employee.Email \u2192 Employee.Name",
  "pa_lookup": "task_assignee email before @",
  "crew_lookup": "crew_type compared with CrewType.Code"
}

                SQL PATTERNS:
                {}

VIEW: AppMasterDB.dbo.WellMonitoringReport
                PURPOSE: Complete well monitoring - MOC, dates, progress, SAP data
                SOURCE TABLES: dbo.WMR, dbo.WMR_TaskPlan_csv_imported, dbo.DesignTrackerCSVImport, dbo.SAP_DRILLING_SEQUENCE, dbo.Revenue, dbo.crews

                KEY COLUMNS:
                {
  "pdo_well_id": {
    "type": "nvarchar",
    "logic": "PRIMARY KEY - unique well identifier"
  },
  "Cluster": {
    "type": "nvarchar",
    "logic": "nimr or marmul"
  },
  "rig_no": {
    "type": "nvarchar",
    "logic": "Drilling rig \u2192 crews.Code"
  },
  "moc_raised": {
    "type": "nvarchar",
    "logic": "YES or Yes"
  },
  "moc_approved": {
    "type": "nvarchar",
    "logic": "YES or Yes"
  },
  "over_all_progress_percentages": {
    "type": "decimal",
    "logic": "0-1 scale, multiply by 100 for %"
  }
}

                BUSINESS LOGIC:
                {
  "target_week": "Latest week minus 1 (second most recent)",
  "taskplan_parsing": "fn_WMR_ParseProgress, fn_WMR_ParseDate",
  "moc_values": "Use IN ('YES', 'Yes', 'yes') - NOT 'Raised'"
}

                SQL PATTERNS:
                {}
